import { useContext } from "react";
import ThemeContext from "../context/ThemeContext";


function Header() {
  const { theme, toggleTheme } = useContext(ThemeContext);

  return (
    <header className={theme}>
      <button onClick={toggleTheme}>
        Mode {theme === "light" ? "🌙" : "☀️"}
      </button>
    </header>
  );
}

export default Header;
